class Solution:
    def maximumScore(self, nums, k):
        n = len(nums)
        MOD = 10 ** 9 + 7

        def prime_score(x):
            s = set()
            d = 2
            while d * d <= x:
                if x % d == 0:
                    s.add(d)
                    while x % d == 0:
                        x //= d
                d += 1
            if x > 1:
                s.add(x)
            return len(s)

        pscore = [prime_score(v) for v in nums]
        count = [0] * n
        for l in range(n):
            best_i = l
            best_score = pscore[l]
            for r in range(l, n):
                if r > l and pscore[r] > best_score:
                    best_score = pscore[r]
                    best_i = r
                count[best_i] += 1
        order = sorted(range(n), key=lambda i: -nums[i])
        remaining = k
        score = 1
        for i in order:
            if remaining <= 0:
                break
            take = min(count[i], remaining)
            score = score * pow(nums[i], take, MOD) % MOD
            remaining -= take
        return score

