class Solution:
    def maximumScore(self, nums, k):
        n = len(nums)
        MOD = 10 ** 9 + 7
        maxv = max(nums)
        spf = list(range(maxv + 1))
        d = 2
        while d * d <= maxv:
            if spf[d] == d:
                for j in range(d * d, maxv + 1, d):
                    if spf[j] == j:
                        spf[j] = d
            d += 1

        def prime_score(x):
            s = set()
            while x > 1:
                p = spf[x]
                s.add(p)
                while x % p == 0:
                    x //= p
            return len(s)

        pscore = [prime_score(v) for v in nums]
        left = [-1] * n
        stack = []
        for i in range(n):
            while stack and pscore[stack[-1]] < pscore[i]:
                stack.pop()
            left[i] = stack[-1] if stack else -1
            stack.append(i)
        right = [n] * n
        stack = []
        for i in range(n - 1, -1, -1):
            while stack and pscore[stack[-1]] <= pscore[i]:
                stack.pop()
            right[i] = stack[-1] if stack else n
            stack.append(i)
        count = [(i - left[i]) * (right[i] - i) for i in range(n)]
        order = sorted(range(n), key=lambda i: -nums[i])
        remaining = k
        score = 1
        for i in order:
            if remaining <= 0:
                break
            take = min(count[i], remaining)
            score = score * pow(nums[i], take, MOD) % MOD
            remaining -= take
        return score

