var maximumScore = function(nums, k) {
    const n = nums.length;
    const MOD = 1000000007n;

    function modpow(base, exp, mod) {
        base = BigInt(base) % mod;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % mod;
            base = (base * base) % mod;
            exp >>= 1n;
        }
        return result;
    }

    const maxv = Math.max(...nums);
    const spf = new Int32Array(maxv + 1);
    for (let i = 0; i <= maxv; i++) spf[i] = i;
    for (let d = 2; d * d <= maxv; d++) {
        if (spf[d] === d) {
            for (let j = d * d; j <= maxv; j += d) {
                if (spf[j] === j) spf[j] = d;
            }
        }
    }
    const pscore = new Array(n);
    for (let idx = 0; idx < n; idx++) {
        let x = nums[idx];
        const seen = new Set();
        while (x > 1) {
            const p = spf[x];
            seen.add(p);
            while (x % p === 0) x = Math.floor(x / p);
        }
        pscore[idx] = seen.size;
    }
    const left = new Array(n).fill(-1);
    let stack = [];
    for (let i = 0; i < n; i++) {
        while (stack.length && pscore[stack[stack.length - 1]] < pscore[i]) stack.pop();
        left[i] = stack.length ? stack[stack.length - 1] : -1;
        stack.push(i);
    }
    const right = new Array(n).fill(n);
    stack = [];
    for (let i = n - 1; i >= 0; i--) {
        while (stack.length && pscore[stack[stack.length - 1]] <= pscore[i]) stack.pop();
        right[i] = stack.length ? stack[stack.length - 1] : n;
        stack.push(i);
    }
    const count = new Array(n);
    for (let i = 0; i < n; i++) count[i] = (i - left[i]) * (right[i] - i);
    const order = Array.from({ length: n }, (_, i) => i).sort((a, b) => nums[b] - nums[a]);
    let remaining = k;
    let score = 1n;
    for (const i of order) {
        if (remaining <= 0) break;
        const take = Math.min(count[i], remaining);
        score = (score * modpow(nums[i], BigInt(take), MOD)) % MOD;
        remaining -= take;
    }
    return Number(score % MOD);
};
